// HasSyncPlan applies the HasEdge predicate on the "sync_plan" edge.
func HasSyncPlan() predicate.AppStripeInvoiceSyncOp {
	return predicate.AppStripeInvoiceSyncOp(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, SyncPlanTable, SyncPlanColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasSyncPlanWith applies the HasEdge predicate on the "sync_plan" edge with a given conditions (other predicates).
func HasSyncPlanWith(preds ...predicate.AppStripeInvoiceSyncPlan) predicate.AppStripeInvoiceSyncOp {
	return predicate.AppStripeInvoiceSyncOp(func(s *sql.Selector) {
		step := newSyncPlanStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.AppStripeInvoiceSyncOp) predicate.AppStripeInvoiceSyncOp {
	return predicate.AppStripeInvoiceSyncOp(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.AppStripeInvoiceSyncOp) predicate.AppStripeInvoiceSyncOp {
	return predicate.AppStripeInvoiceSyncOp(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.AppStripeInvoiceSyncOp) predicate.AppStripeInvoiceSyncOp {
	return predicate.AppStripeInvoiceSyncOp(sql.NotPredicates(p))
}
